always @(posedge clk or posedge rst) begin
if (rst) data_out <= 0;
else data_out <= data_out_reg;
end

always @(posedge clk) begin
case(data_in[3:0])
4'b0000: data_out_reg = {24'b0, data_in[7:0]};
default: data_out_reg = 32'd0;
endcase
end

always @ (en or rst or data_in)
if (rst)
data_out <= 0;
else if (!en)
data_out <= 0;
else
data_out <= data_in;

